transform_js:
const dataMap = {};
let root = {};
// 階層データ（再帰ツリー）を構築
rawData.rows.forEach(r => {
  dataMap[r.id] = { name: r.id, value: r.value, children: [] };
});
rawData.rows.forEach(r => {
  if (r.parent && dataMap[r.parent]) {
    dataMap[r.parent].children.push(dataMap[r.id]);
  } else {
    root = dataMap[r.id];
  }
});
// echarts の data はルート配列を要求する
transformedData = [root];

echarts_js:
option = {
  tooltip: {
    trigger: 'item',
    triggerOn: 'mousemove'
  },
  title: {
     text: 'Organization Hierarchy (Tree)',
     left: 'center',
     top: '5%'
  },
  series: [
    {
      type: 'tree',
      data: transformedData,
      top: '10%',
      left: '7%',
      bottom: '5%',
      right: '20%',
      symbolSize: 12,
      // 左から右へのレイアウト展開
      orient: 'LR',
      label: {
        position: 'left',
        verticalAlign: 'middle',
        align: 'right',
        fontSize: 14,
        fontWeight: 'bold',
        padding: [0, 5]
      },
      leaves: {
        label: {
          position: 'right',
          verticalAlign: 'middle',
          align: 'left'
        }
      },
      expandAndCollapse: true,
      animationDuration: 550,
      animationDurationUpdate: 750
    }
  ]
};
